import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;

public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
    List<String> validCoupons = new ArrayList<>();
    String[] validBusinessLines = {"electronics", "grocery", "pharmacy", "restaurant"};

    for (int i = 0; i < code.length; i++) {
        String currentCode = code[i];
        String currentBusinessLine = businessLine[i];
        boolean currentIsActive = isActive[i];

        // Check if code is valid (non-empty and only alphanumeric + underscore)
        boolean isCodeValid = currentCode != null && !currentCode.isEmpty() && currentCode.matches("^[a-zA-Z0-9_]+$");

        // Check if business line is valid
        boolean isBusinessLineValid = false;
        for (String validBL : validBusinessLines) {
            if (validBL.equals(currentBusinessLine)) {
                isBusinessLineValid = true;
                break;
            }
        }

        // Check if coupon is active
        boolean isActiveValid = currentIsActive;

        if (isCodeValid && isBusinessLineValid && isActiveValid) {
            validCoupons.add(currentCode + ":" + currentBusinessLine);
        }
    }

    // Sort the valid coupons
    Collections.sort(validCoupons, new Comparator<String>() {
        @Override
        public int compare(String a, String b) {
            String[] partsA = a.split(":");
            String[] partsB = b.split(":");
            String businessLineA = partsA[1];
            String businessLineB = partsB[1];
            String codeA = partsA[0];
            String codeB = partsB[0];

            int orderA = getBusinessLineOrder(businessLineA);
            int orderB = getBusinessLineOrder(businessLineB);

            if (orderA != orderB) {
                return Integer.compare(orderA, orderB);
            } else {
                return codeA.compareTo(codeB);
            }
        }
    });

    // Extract the codes in order
    String[] result = new String[validCoupons.size()];
    for (int i = 0; i < validCoupons.size(); i++) {
        result[i] = validCoupons.get(i).split(":")[0];
    }

    return result;
}

private static int getBusinessLineOrder(String businessLine) {
    switch (businessLine) {
        case "electronics": return 0;
        case "grocery": return 1;
        case "pharmacy": return 2;
        case "restaurant": return 3;
        default: return -1;
    }
}
