        // Check if business line is valid
        const isBusinessLineValid = validBusinessLines.has(currentBusinessLine);

        // Check if coupon is active
        const isActiveValid = currentIsActive === true;

        if (isCodeValid && isBusinessLineValid && isActiveValid) {
            validCoupons.push({
                code: currentCode,
                businessLine: currentBusinessLine
            });
        }
    }

    // Sort the valid coupons
    validCoupons.sort((a, b) => {
        const orderA = businessLineOrder[a.businessLine];
        const orderB = businessLineOrder[b.businessLine];
        if (orderA !== orderB) {
