public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
    List<String> validCoupons = new ArrayList<>();
    String[] validBusinessLines = {"electronics", "grocery", "pharmacy", "restaurant"};
    Pattern pattern = Pattern.compile("^[a-zA-Z0-9_]+$");

    for (int i = 0; i < code.length; i++) {
        String currentCode = code[i];
        String currentBusinessLine = businessLine[i];
        boolean currentIsActive = isActive[i];

        boolean isCodeValid = currentCode != null && !currentCode.isEmpty() && pattern.matcher(currentCode).matches();
        boolean isBusinessLineValid = false;
        for (String validBL : validBusinessLines) {
            if (validBL.equals(currentBusinessLine)) {
                isBusinessLineValid = true;
                break;
            }
        }
        boolean isActiveValid = currentIsActive;

        if (isCodeValid && isBusinessLineValid && isActiveValid) {
            validCoupons.add(currentCode + ":" + currentBusinessLine);
        }
    }

    validCoupons.sort((a, b) -> {
        String[] partsA = a.split(":");
        String[] partsB = b.split(":");
        String blA = partsA[1];
        String blB = partsB[1];
        int orderA = -1;
        int orderB = -1;
        for (int i = 0; i < validBusinessLines.length; i++) {
            if (validBusinessLines[i].equals(blA)) {
                orderA = i;
            }
            if (validBusinessLines[i].equals(blB)) {
                orderB = i;
            }
        }
        if (orderA != orderB) {
            return Integer.compare(orderA, orderB);
        } else {
            return partsA[0].compareTo(partsB[0]);
        }
    });

    String[] result = new String[validCoupons.size()];
    for (int i = 0; i < result.length; i++) {
        result[i] = validCoupons.get(i).split(":")[0];
